class Solution {
public:
    int minimumScore(string s, string t) {
        int m = s.size(), n = t.size();
        vector<int> pre(n, m), suf(n, -1);
        int j = 0;
        for (int i = 0; i < m && j < n; ++i) {
            if (s[i] == t[j]) pre[j++] = i;
        }
        j = n - 1;
        for (int i = m - 1; i >= 0 && j >= 0; --i) {
            if (s[i] == t[j]) suf[j--] = i;
        }
        int res = n ? n : 0;
        for (int i = 0, j = 0; i < n; ++i) {
            if (pre[i] != m) {
                while (j < n && (suf[j] == -1 || pre[i] >= suf[j])) ++j;
                if (j < n) res = min(res, suf[j] - pre[i] + 1);
            }
        }
        return res;
    }
};
